mapper.select:
select n.*, u.user_code, u.user_name, u.role_name, ur.user_name as 'recomusername', ur.user_code as 'recomusercode' from t_news n left join tz_user u on n.user_id =u.user_id left join tz_user ur on u.user_recom = ur.user_id
where 1=1
and n.title like CONCAT('%', #{title}, '%')
and n.language=#{language}
and u.user_code=#{userCode} or u.user_name=#{userCode}
order by n.create_time desc
